// React fiber에서 zustand store state 추출
const btn = document.querySelector('[data-testid="order-type-dine-in"]');
if (!btn) return 'button not found';
const fiberKey = Object.keys(btn).find(k => k.startsWith('__reactFiber') || k.startsWith('__reactInternals'));
let fiber = btn[fiberKey];
let state = null;
while (fiber) {
  if (fiber.memoizedState && fiber.memoizedState.queue) {
    try {
      // find zustand store
      let s = fiber.memoizedState;
      while (s) {
        if (s.memoizedState && typeof s.memoizedState === 'object' && s.memoizedState.step) {
          state = { step: s.memoizedState.step, isIdle: s.memoizedState.isIdle };
          break;
        }
        s = s.next;
      }
    } catch(e) {}
  }
  if (state) break;
  fiber = fiber.return;
}
JSON.stringify(state || 'not found');

